import React, { useEffect, useState } from 'react';
import {
    Box, Card, CardContent, Typography,
    Table, TableHead, TableRow, TableCell,
    TableBody, Skeleton, Alert, Chip
} from '@mui/material';

import api from '../../services/api';

const DailySummary = () => {

    const [data, setData] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    // ================= FETCH =================
    const fetchSummary = async () => {
        try {
            const res = await api.getDailySummaryReport?.()
                || await api.getDailySummary();

            const result = res?.data?.results || res?.data || [];

            // fallback dummy if empty
            if (!result.length) {
                setData([
                    {
                        date: "2026-04-01",
                        punch_count: 5,
                        first_punch: "09:15",
                        last_punch: "18:10",
                        total_distance: 12.5,
                        duration: "8h 30m",
                        collection: 2500
                    },
                    {
                        date: "2026-03-31",
                        punch_count: 3,
                        first_punch: "10:00",
                        last_punch: "16:00",
                        total_distance: 6.2,
                        duration: "5h 30m",
                        collection: 1200
                    }
                ]);
            } else {
                setData(result);
            }

        } catch (err) {
            console.error(err);
            setError("Failed to load summary");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchSummary();
    }, []);

    const safe = (v) => (v ? Number(v).toFixed(2) : '0.00');

    return (
        <Box sx={{ p: 3 }}>

            <Typography variant="h5" sx={{ mb: 2 }}>
                Daily Summary Report
            </Typography>

            {error && <Alert severity="error">{error}</Alert>}

            <Card>
                <CardContent>

                    {loading ? (
                        <Skeleton variant="rectangular" height={200} />
                    ) : (
                        <Table size="small">

                            <TableHead>
                                <TableRow sx={{ backgroundColor: '#f5f5f5' }}>
                                    <TableCell>Date</TableCell>
                                    <TableCell>Punch Count</TableCell>
                                    <TableCell>First Punch</TableCell>
                                    <TableCell>Last Punch</TableCell>
                                    <TableCell>Distance</TableCell>
                                    <TableCell>Working Time</TableCell>
                                    <TableCell>Collection</TableCell>
                                    <TableCell>Status</TableCell>
                                </TableRow>
                            </TableHead>

                            <TableBody>
                                {data.map((d, i) => {

                                    const status =
                                        d.punch_count === 0 ? 'No Activity'
                                            : d.total_distance > 10 ? 'Active'
                                                : 'Low Activity';

                                    return (
                                        <TableRow key={i} hover>

                                            <TableCell>
                                                {new Date(d.date).toLocaleDateString()}
                                            </TableCell>

                                            <TableCell>{d.punch_count}</TableCell>

                                            <TableCell>{d.first_punch || '--'}</TableCell>

                                            <TableCell>{d.last_punch || '--'}</TableCell>

                                            <TableCell>
                                                {safe(d.total_distance)} km
                                            </TableCell>

                                            <TableCell>{d.duration || '--'}</TableCell>

                                            <TableCell>
                                                ₹ {safe(d.collection)}
                                            </TableCell>

                                            <TableCell>
                                                <Chip
                                                    label={status}
                                                    color={
                                                        status === 'Active'
                                                            ? 'success'
                                                            : status === 'Low Activity'
                                                                ? 'warning'
                                                                : 'default'
                                                    }
                                                    size="small"
                                                />
                                            </TableCell>

                                        </TableRow>
                                    );
                                })}
                            </TableBody>

                        </Table>
                    )}

                </CardContent>
            </Card>

        </Box>
    );

};

export default DailySummary;